+// ActiveHost returns the currently active host:port being used for Dolt connections.
+func (m *DoltServerManager) ActiveHost() string {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+	if len(m.allHosts) == 0 {
+		return ""
+	}
+	return m.allHosts[m.activeHostIdx]
+}
