+	t.Run("GT_ROOT also works", func(t *testing.T) {
+		t.Setenv("GT_TOWN_ROOT", "")
+		t.Setenv("GT_ROOT", outerTown)
+		got := detectTownRoot(nestedRig)
+		if got != outerTown {
